SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, TRY_CAST(left(CAST("ENTRY_DATE" AS VARCHAR), 10) AS DATE) AS date, NULLIF("ENTITY_NAME", '') AS entity_name, NULLIF("ENTITY_TYPE", '') AS entity_type, NULLIF("TYPE_MODEL", '') AS type_model, TRY_CAST("DIST_FLOWN_KM" AS DOUBLE) AS dist_flown_km, TRY_CAST("DIST_DIRECT_KM" AS DOUBLE) AS dist_direct_km, TRY_CAST("DIST_ACHIEVED_KM" AS DOUBLE) AS dist_achieved_km FROM "eurocontrol-hfe") WHERE date IS NOT NULL
